\chapter*{\S\space 49. --- Homomorphismes de $\mathcal{M}_{0,3}$, les groupes $\mathcal{M}_{g,\nu}$ généraux}
\addcontentsline{toc}{section}{49. Homomorphismes de $\mathcal{M}_{0,3}$, les groupes $\mathcal{M}_{g,\nu}$ généraux}
\label{sec:49}
\section*{}

\textbf{I)} Considérons un sous-groupe fermé $\mathcal{G}$ de $\mathcal{M}_{0,3}$, contenant $\mathfrak{S}^{+\wedge}_{0,3}$, donc image inverse d'un sous-groupe fermé de $\widetilde{\Gamma}_{0,3}$. On suppose que celui-ci est ``sphysien''\footnote{Tout ce début de section n'est pas à sa place, et devrait être déplacé plus loin. Peut-être faudrait-il plutôt retravailler directement la suite du \S\ 48, pour y faire figurer \emph{mutatis mutandis} les sorites de cette section.} ``gros'' --- disons qu'il contient un sous-groupe d'indice fini de $\widetilde{\Gamma}_{\mathbf{Q}} \subset \widetilde{\Gamma}_{0,3}$. Pour le moment, on suppose pour simplifier que $\mathcal{G} \subset \Ker \varepsilon_3$. En résumé
$$
\mathfrak{S}^{+\wedge}_{0,3} \subset \mathcal{G} \subset \widetilde{\mathcal{M}}_{0,3}, \quad u \in \mathcal{G} \Rightarrow \mu(u) \equiv 1 \,(3) \leqno{(1)}
$$
Cette dernière hypothèse signifie donc que pour tout $u \in \mathcal{G}$, on a $\alpha_0^u \in \mathfrak{S}^{+\wedge}_{0,3}$, donc on a
$$
\mathcal{G} \xrightarrow[\beta_0]{\alpha_0} \mathfrak{S}^{+\wedge}_{0,3} , \leqno{(2)}
$$
constitués par
$$
\begin{cases} u(\rho) = \operatorname{int}(\alpha_0)\rho \\ u(\sigma) = \operatorname{int}(\beta_0)\sigma \end{cases} \qquad \alpha_0 = \alpha_0^u,\ \beta_0 = \beta_0^u . \leqno{(2')}
$$
On considère
$$
\begin{cases} \mathcal{G}(0) = \mathcal{G} \cap \widetilde{\mathcal{M}}_{0,3}(0) \\ \mathcal{G}[0] = \mathcal{G} \cap \widetilde{\mathcal{M}}_{0,3}[0] = \operatorname{Norm}_{\mathcal{G}}(L_0^{\mathfrak{S}}) \end{cases} \leqno{(3)}
$$
de sorte que
$$
\mathcal{G} = \mathcal{G}(0) \cdot \mathfrak{S}^{+\wedge}_{0,3} \quad \text{(par suite sous-disant)} \leqno{(4)}
$$
$$
\mathcal{G}[0] = \mathcal{G}(0) \cdot L_0^{\mathfrak{S}} \leqno{(5)}
$$
$$
\mathcal{G}[0] \cap \mathfrak{S}^{+\wedge}_{0,3} = L_0^{\mathfrak{S}} . \leqno{(6)}
$$
On a posé
$$
L_0^{\mathfrak{S}} = \text{sous-groupe fermé de } \mathfrak{S}^{+\wedge}_{0,3} \text{ engendré} \leqno{(7)}
$$
et on dispose de même $L_1^{\mathfrak{S}}$, $L_\infty^{\mathfrak{S}}$.

Considérons un groupe profini $\mathcal{M}$, et un homomorphisme surjectif (continu)
$$
\varphi : \mathcal{G} \longrightarrow \mathcal{M} . \leqno{(8)}
$$
On pose
$$
\begin{cases} \varphi(\mathfrak{S}^{+\wedge}_{0,3}) = \mathfrak{S} \quad \text{sous-groupe distingué de } \mathcal{M} \\ \varphi(\mathcal{G}(0)) = \mathcal{M}(0) \\ \varphi(\mathcal{G}[0]) = \mathcal{M}[0] \\ \varphi(L_0^{\mathfrak{S}}) = L_0^{\mathfrak{S}} . \end{cases} \leqno{(9)}
$$
Donc ce sont des sous-groupes fermés de $\mathcal{M}$, satisfaisant
$$
\mathcal{M}(0) \subset \mathcal{M}[0] \subset \operatorname{Norm}_{\mathcal{M}}(L_0) \leqno{(10)}
$$
$$
L_0 \subset \mathfrak{S} \cap \mathcal{M}[0] . \leqno{(11)}
$$

Pour alléger le langage, on désignera encore par $\rho, \sigma, \varepsilon_0, \varepsilon_1, \ldots$ les images de ces éléments dans $\mathfrak{S}$, qui y satisfont donc les relations connues dans $\mathfrak{S}^{+\wedge}_{0,3}$, en particulier
$$
\sigma^2 = \rho^3 = 1, \quad \sigma\rho = \varepsilon_0, \quad \rho^\sigma = \varepsilon_1, \quad \varepsilon_1 = \sigma(\varepsilon_0) = \rho(\varepsilon_0) . \leqno{(12)}
$$
Les restrictions des applications $\alpha_0, \beta_0$ de (2, 2') à $\mathcal{M}_{\rho,\sigma}[0]$ seront plutôt notées $\alpha, \beta$, où $\alpha, \beta$ sont en fait des applications
$$
S\mathcal{G} \defeq \substack{\text{schéma de} \\ \text{par } L_0, \text{sous-} \mathcal{G} \\ \text{inverse de } S\mathcal{G} \\ = S\mathcal{M}_{\mathcal{G}}} = \{(u,f) \in \mathcal{G} \times \mathfrak{S}^{+\wedge}_{0,3} \mid fu \in \mathcal{G}[0]\} \xrightarrow[\beta]{\alpha} \mathfrak{S}^{+\wedge}_{0,3} \leqno{(13)}
$$
dont on regarde les restrictions au sous-groupe ($\isom \mathcal{M}_{\rho,\sigma}[0]$) de $S\mathcal{G}$ défini par la relation $f = 1$. Composant avec $p : \mathcal{G}[0] \rightrightarrows \mathfrak{S}^{+\wedge}_{0,3}$ avec $\varphi | \mathfrak{S}^{+\wedge}_{0,3}$, on trouve des applications, encore notées $\alpha, \beta$ (i.e.\ $\alpha^M, \beta^M$ en cas de confusion possible)
$$
\mathcal{G}[0] \xrightarrow[\beta]{\alpha} \mathfrak{S} \leqno{(14)}
$$
satisfaisant aux
$$
\begin{cases} u(\rho) = \operatorname{int}(\alpha)\rho \\ u(\sigma) = \operatorname{int}(\beta)\sigma \end{cases} \quad \text{pour } u \in \mathcal{M}[0] \text{ de forme } \varphi(u_0), \text{ et } \alpha = \underline{\alpha}(u_0), \beta = \underline{\beta}(u_0). \leqno{(15)}
$$
